/// 1000-INITIALIZE
fn p_1000_initialize(state: &mut ProgramState) {
    {
    let _now = Local::now();
    let _ds = _now.format("%y%m%d").to_string();
    state.ws_variables.current_date = _ds.parse().unwrap_or_default();
    }
    // ACCEPT CURRENT-YYDDD FROM DAY
    println!("{}", "STARTING PROGRAM DBUNLDGS::");
    println!("{}", "*-------------------------------------*");
    println!("{}{}", "TODAYS DATE            :", state.ws_variables.current_date);
    println!("{}", " ");
}

