/// 2000-FIND-NEXT-AUTH-SUMMARY
fn p_2000_find_next_auth_summary(state: &mut ProgramState) {
    state.pautbpcb.paut_pcb_status = Default::default();
    {
        let mut _p1 = (state.func_codes.func_gn).clone();
        let mut _p2 = (state.pautbpcb).clone();
        let mut _p3 = (state.pending_auth_summary).clone();
        let mut _p4 = (state.root_unqual_ssa).clone();
        cbltdli(&mut _p1, &mut _p2, &mut _p3, &mut _p4);
        state.func_codes.func_gn = _p1;
        state.pautbpcb = _p2;
        state.pending_auth_summary = _p3;
        state.root_unqual_ssa = _p4;
    }
    if state.pautbpcb.paut_pcb_status.trimmed() == " " {
        state.ws_variables.ws_no_sumry_read += 1 as i32;
        state.ws_variables.ws_auth_smry_proc_cnt += 1 as u32;
        state.opfil1_rec = FixedString::copy_from(&state.pending_auth_summary);
        state.opfil2_rec.root_seg_key = Default::default();
        state.opfil2_rec.child_seg_rec = Default::default();
        // SKIP: unresolved ref
        if state.pending_auth_summary.pa_acct_id.value != 0 {
        }
        p_3100_insert_parent_seg_gsam(state);
        p_3100_exit(state);
        state.ws_variables.ws_end_of_child_seg = Default::default();
        p_3000_find_next_auth_dtl(state);
        p_3000_exit(state);
    }
    if &format!("{}", state.pautbpcb.paut_pcb_status) == &"GB".to_string() {
        state.ws_variables.ws_end_of_authdb_flag = "Y".into();
        state.ws_variables.ws_end_of_root_seg = "Y".into();
    }
    // SKIP: unresolved condition
}

